INSERT INTO `wp_aioseo_notifications` VALUES (1, '6a0e7224f1adb', NULL, 'Have you connected your site to Google Search Console?', 'AIOSEO can now verify whether your site is correctly verified with Google Search Console and that your sitemaps have been submitted correctly. Connect with Google Search Console now to ensure your content is being added to Google as soon as possible for increased rankings.', 'warning', '[\"all\"]', NULL, 'search-console-site-not-connected', '2026-05-21 02:47:00', NULL, 'Connect to Google Search Console', 'https://route#aioseo-settings&aioseo-scroll=google-search-console-settings&aioseo-highlight=google-search-console-settings:webmaster-tools?activetool=googleSearchConsole', NULL, NULL, 0, 0, '2026-05-21 02:47:00', '2026-05-21 02:47:00');
INSERT INTO `wp_aioseo_notifications` VALUES (2, '6a0e72784e227', NULL, 'Memorial Day Flash Sale: Up to 60% Off! 🇺🇸', '<img src=\"data:image/webp;base64,\" alt=\"\" class=\"wp-image-1440\"/>\n\n<p>Celebrate this Memorial Day with up to 60% off all AIOSEO plans and upgrades. 🎉</p>\n\n<p>If you\'ve been meaning to unlock more powerful SEO tools, consider this your sign. Real-time SEO scoring for every post. AI writing tools inside WordPress. Automatic redirect management and schema markup. Rich snippets without code.</p>\n\n<p>AIOSEO makes SEO easy, so you can focus on what matters most: growing your business.</p>\n\n<p>Limited-time deal. ⏳</p>', 'success', '[\"4-x\",\"lite\"]', 1439, NULL, '2026-05-25 00:00:00', '2026-05-27 00:00:00', 'Get AIOSEO Pro', 'https://aioseo.com/pricing/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=memorial-day-2026-v4-x-lite', NULL, NULL, 0, 0, '2026-05-21 02:48:24', '2026-05-22 02:48:33');
