INSERT INTO `wp_comments` VALUES (1, 1, '一位 WordPress 评论者', 'wapuu@wordpress.example', 'https://cn.wordpress.org/', '', '2026-05-21 09:36:03', '2026-05-21 01:36:03', '您好，这是一条评论。若需要审核、编辑或删除评论，请访问仪表盘的评论界面。评论者头像来自 <a href=\"https://cn.gravatar.com/\">Gravatar</a>。', 0, '1', '', 'comment', 0, 0);
INSERT INTO `wp_comments` VALUES (2, 221, 'A WordPress Commenter', 'wapuu@wordpress.example', 'https://wordpress.org/', '', '2023-12-20 16:37:16', '2023-12-20 16:37:16', 'Hi, this is a comment.\nTo get started with moderating, editing, and deleting comments, please visit the Comments screen in the dashboard.\nCommenter avatars come from <a href=\"https://en.gravatar.com/\" rel=\"nofollow ugc\">Gravatar</a>.', 0, '1', '', 'comment', 0, 0);
