  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `type` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NULL DEFAULT NULL,
  `hash_id` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `main_meta_id` bigint(20) UNSIGNED NOT NULL COMMENT 'Id of main field. to represent the main meta field',
  `post_id` bigint(20) UNSIGNED NOT NULL,
  `referer` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `referer_title` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NULL DEFAULT NULL,
  `element_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `form_name` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `campaign_id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NULL DEFAULT NULL,
  `user_ip` varchar(46) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `user_agent` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `actions_count` int(11) NULL DEFAULT 0,
  `actions_succeeded_count` int(11) NULL DEFAULT 0,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `is_read` tinyint(1) NOT NULL DEFAULT 0,
  `meta` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_520_ci NULL,
  `created_at_gmt` datetime NOT NULL,
  `updated_at_gmt` datetime NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `hash_id_unique_index`(`hash_id`) USING BTREE,
  INDEX `main_meta_id_index`(`main_meta_id`) USING BTREE,
  INDEX `hash_id_index`(`hash_id`) USING BTREE,
  INDEX `type_index`(`type`) USING BTREE,
  INDEX `post_id_index`(`post_id`) USING BTREE,
  INDEX `element_id_index`(`element_id`) USING BTREE,
  INDEX `campaign_id_index`(`campaign_id`) USING BTREE,
  INDEX `user_id_index`(`user_id`) USING BTREE,
  INDEX `user_ip_index`(`user_ip`) USING BTREE,
  INDEX `status_index`(`status`) USING BTREE,
  INDEX `is_read_index`(`is_read`) USING BTREE,
  INDEX `created_at_gmt_index`(`created_at_gmt`) USING BTREE,
  INDEX `updated_at_gmt_index`(`updated_at_gmt`) USING BTREE,
  INDEX `created_at_index`(`created_at`) USING BTREE,
  INDEX `updated_at_index`(`updated_at`) USING BTREE,
  INDEX `referer_index`(`referer`(191)) USING BTREE,
  INDEX `referer_title_index`(`referer_title`(191)) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_520_ci ROW_FORMAT = Dynamic;

